        }

        /* Chatbot Widget Styles */
        .chatbot-widget {
          position: fixed;
          bottom: 24px;
          right: 24px;
          z-index: 1000;
        }

        .chatbot-toggle {
          width: 56px;
          height: 56px;
          border-radius: 50%;
          background: #2563eb;
          color: white;
          border: none;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          box-shadow: 0 4px 20px rgba(37, 99, 235, 0.3);
          transition: all 0.3s ease;
          position: relative;
        }

        .chatbot-toggle:hover {
          background: #1d4ed8;
          transform: scale(1.05);
        }

        .chat-notification {
          position: absolute;
          top: -4px;
          right: -4px;
          background: #ef4444;
          color: white;
          border-radius: 50%;
          width: 20px;
          height: 20px;
          font-size: 11px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: 600;
        }

        .chatbot-container {
          position: absolute;
          bottom: 70px;
          right: 0;
          width: 380px;
          height: 600px;
          background: white;
          border-radius: 16px;
          box-shadow: 0 10px 40px rgba(0, 0, 0, 0.1);
          display: flex;
          flex-direction: column;
          opacity: 0;
          transform: translateY(20px);
          pointer-events: none;
          transition: all 0.3s ease;
          overflow: hidden;
        }

        .chatbot-widget.open .chatbot-container {
          opacity: 1;
          transform: translateY(0);
          pointer-events: all;
        }

        .chat-header {
          padding: 16px;
          border-bottom: 1px solid #eef2ff;
          display: flex;
          justify-content: space-between;
          align-items: center;
          background: white;
        }

        .chat-header-left {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .chat-header h3 {
          margin: 0;
          font-size: 16px;
          font-weight: 600;
        }

        .chat-subtitle {
          margin: 0;
          font-size: 12px;
          color: #64748b;
        }

        .chat-clear {
          background: none;
          border: 1px solid #e2e8f0;
          color: #64748b;
          padding: 6px 12px;
          border-radius: 6px;
          font-size: 12px;
          cursor: pointer;
