import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { 
  Loader2, 
  Send, 
  Bot, 
  X, 
  ChevronRight, 
  BookOpen, 
  Calendar, 
  CreditCard, 
  CheckCircle,
  AlertCircle,
  Clock,
  TrendingUp,
  MessageSquare
} from 'lucide-react';

const StudentDashboard = () => {
  const [payload, setPayload] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAllSemesters, setShowAllSemesters] = useState(false);
  
  // Chatbot State
  const [chatbotOpen, setChatbotOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [userInput, setUserInput] = useState('');
  const [isAiTyping, setIsAiTyping] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const [chatHistory, setChatHistory] = useState([]);
  const messagesEndRef = useRef(null);
  const chatContainerRef = useRef(null);

  useEffect(() => {
    loadDashboard();
    loadChatSuggestions();
    // eslint-disable-next-line
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const loadDashboard = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.get('http://localhost:65000/api/students/getStudentDashboard', {
        withCredentials: true
      });
      setPayload(res.data);
      
      // Preload chatbot with student context
      if (res.data.student) {
        initializeChatbotWithContext(res.data);
      }
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || 'Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  const initializeChatbotWithContext = (studentData) => {
    // Add welcome message with context
    const welcomeMessage = {
      id: Date.now(),
      type: 'ai',
      content: `Hi ${studentData.student.name.fullName}! 👋 I'm your AI assistant. I can help you with:\n• Fee details & payments\n• Attendance & grades\n• Course schedule\n• Assignments & deadlines\n• Academic progress\n\nAsk me anything about your student account!`,
      timestamp: new Date().toISOString(),
      isSystem: true
    };
    
    setMessages([welcomeMessage]);
  };

  const loadChatSuggestions = async () => {
    try {
      const response = await axios.get('http://localhost:65000/api/chatbot/suggestions', {
        withCredentials: true
      });
      setSuggestions(response.data.suggestions || getDefaultSuggestions());
    } catch (error) {
      setSuggestions(getDefaultSuggestions());
    }
  };

  const getDefaultSuggestions = () => [
    "What are my pending fees?",
    "Show today's schedule",
    "What's my attendance percentage?",
    "View my assignments",
    "What is my current GPA?",
    "When are my next exams?"
  ];

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (message = userInput) => {
    if (!message.trim() || isAiTyping) return;

    const userMessage = message.trim();
    setUserInput('');
    
    // Add user message
    const newUserMessage = {
      id: Date.now(),
      type: 'user',
      content: userMessage,
      timestamp: new Date().toISOString()
    };
    
    setMessages(prev => [...prev, newUserMessage]);
    setIsAiTyping(true);

    try {
      const response = await axios.post('http://localhost:65000/api/chatbot/ask', 
        { question: userMessage },
        { 
          withCredentials: true,
          timeout: 30000 // 30 second timeout
        }
      );

      const aiMessage = {
        id: Date.now() + 1,
        type: 'ai',
        content: response.data.answer,
        timestamp: new Date().toISOString(),
        responseTime: response.data.responseTime
      };

      setMessages(prev => [...prev, aiMessage]);
      
      // Update chat history
      setChatHistory(prev => [
        ...prev.slice(-9), // Keep last 10
        { question: userMessage, answer: response.data.answer }
      ]);

    } catch (error) {
      console.error('Chatbot error:', error);
      
      const errorMessage = {
        id: Date.now() + 1,
        type: 'ai',
        content: error.response?.status === 504 
          ? "I'm taking a bit longer than usual. Please try again with a simpler question or try again in a moment."
          : "I'm having trouble connecting right now. You can check your dashboard for the latest information, or try again in a moment.",
        timestamp: new Date().toISOString(),
        isError: true
      };
      
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsAiTyping(false);
    }
  };

  const handleQuickAction = (action) => {
    switch(action) {
      case 'fees':
        handleSendMessage("Show my fee summary");
        break;
      case 'attendance':
        handleSendMessage("What's my attendance percentage?");
        break;
      case 'schedule':
        handleSendMessage("Show today's schedule");
        break;
      case 'assignments':
        handleSendMessage("What assignments are pending?");
        break;
      case 'gpa':
        handleSendMessage("What is my current GPA?");
        break;
      case 'progress':
        handleSendMessage("Show my academic progress");
        break;
      default:
        handleSendMessage(action);
    }
  };

  const clearChat = async () => {
    try {
      await axios.post('http://localhost:65000/api/chatbot/clear', {}, {
        withCredentials: true
      });
      setMessages([]);
      initializeChatbotWithContext(payload || { student: { name: { fullName: '' } } });
    } catch (error) {
      console.log('Failed to clear chat:', error);
    }
  };

  const getDashboardInsights = () => {
    if (!payload) return [];
    
    const insights = [];
    const { academicProgress, student } = payload;
    
    // GPA insight
    if (academicProgress.cumulativeGPA && academicProgress.cumulativeGPA < 2.0) {
      insights.push({
        type: 'warning',
        icon: <AlertCircle size={16} />,
        text: 'Your GPA is below 2.0. Consider meeting with your advisor.',
        action: () => handleSendMessage("How can I improve my GPA?")
      });
    }
    
    // Attendance insight
    if (student.scholarship?.isApplicant && student.scholarship?.percentage > 0) {
      insights.push({
        type: 'info',
        icon: <TrendingUp size={16} />,
        text: `You have a ${student.scholarship.percentage}% scholarship. Keep up the good work!`,
        action: () => handleSendMessage("Show my scholarship details")
      });
    }
    
    // Progress insight
    if (academicProgress.completionPercentage > 75) {
      insights.push({
        type: 'success',
        icon: <CheckCircle size={16} />,
        text: `Great progress! You've completed ${academicProgress.completionPercentage}% of your degree.`,
        action: () => handleSendMessage("When will I graduate?")
      });
    }
    
    return insights.slice(0, 3); // Max 3 insights
  };

  if (loading) {
    return (
      <div className="loader-container">
        <Loader2 className="loader-icon" />
        <style>{`
          .loader-container { 
            height: 100vh; 
            display: flex; 
            align-items: center; 
            justify-content: center; 
            background: #f3f6fb; 
          }
          .loader-icon { 
            width: 56px; 
            height: 56px; 
            color: #2563eb; 
            animation: spin 1s linear infinite; 
          }
          @keyframes spin { 
            from { transform: rotate(0); } 
            to { transform: rotate(360deg); } 
          }
        `}</style>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-box">
        <h3>Error</h3>
        <p>{error}</p>
        <button onClick={loadDashboard}>Retry</button>
        <style>{`
          .error-box { 
            padding: 20px; 
            border-radius: 12px; 
            background: #fff1f2; 
            color: #9f1239; 
            margin: 20px; 
            text-align: center; 
          }
          .error-box button { 
            margin-top: 10px; 
            padding: 8px 16px; 
            background: #2563eb; 
            color: white; 
            border: none; 
            border-radius: 8px; 
            cursor: pointer; 
          }
        `}</style>
      </div>
    );
  }

  if (!payload) {
    return <p>No data returned from API.</p>;
  }

  const { student, academicProgress } = payload;
  const current = academicProgress.currentSemesterDetails || {};
  const percentProgress = Math.min(
    100,
    Math.round((academicProgress.totalCreditsEarned / Math.max(1, academicProgress.totalCreditsRequired)) * 100)
  );
  
  const insights = getDashboardInsights();

  return (
    <div className="dashboard-root">
      {/* Chatbot Widget */}
      <div className={`chatbot-widget ${chatbotOpen ? 'open' : ''}`}>
        {/* Chatbot Toggle Button */}
        <button 
          className="chatbot-toggle"
          onClick={() => setChatbotOpen(!chatbotOpen)}
        >
          {chatbotOpen ? <X size={20} /> : <MessageSquare size={20} />}
          {!chatbotOpen && messages.length > 0 && (
            <span className="chat-notification">{messages.length}</span>
          )}
        </button>

        {/* Chatbot Interface */}
        <div className="chatbot-container">
          {/* Chat Header */}
          <div className="chat-header">
            <div className="chat-header-left">
              <Bot size={20} />
              <div>
                <h3>AI Assistant</h3>
                <p className="chat-subtitle">Ask me anything about your student account</p>
              </div>
            </div>
            <button className="chat-clear" onClick={clearChat}>
              Clear Chat
            </button>
          </div>

          {/* Chat Messages */}
          <div className="chat-messages" ref={chatContainerRef}>
            {messages.map((message) => (
              <div 
                key={message.id} 
                className={`chat-message ${message.type} ${message.isSystem ? 'system' : ''} ${message.isError ? 'error' : ''}`}
              >
                {message.type === 'ai' && (
                  <div className="message-avatar">
                    <Bot size={16} />
                  </div>
                )}
                <div className="message-content">
                  <div className="message-text">
                    {message.content.split('\n').map((line, i) => (
                      <React.Fragment key={i}>
                        {line}
                        {i < message.content.split('\n').length - 1 && <br />}
                      </React.Fragment>
                    ))}
                  </div>
                  <div className="message-meta">
                    <span className="message-time">
                      {new Date(message.timestamp).toLocaleTimeString([], { 
                        hour: '2-digit', 
                        minute: '2-digit' 
                      })}
                    </span>
                    {message.responseTime && (
                      <span className="message-duration">
                        <Clock size={12} /> {message.responseTime}ms
                      </span>
                    )}
                  </div>
                </div>
              </div>
            ))}
            
            {isAiTyping && (
              <div className="chat-message ai">
                <div className="message-avatar">
                  <Bot size={16} />
                </div>
                <div className="message-content">
                  <div className="typing-indicator">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                </div>
              </div>
            )}
            
            <div ref={messagesEndRef} />
          </div>

          {/* Quick Actions */}
          <div className="chat-quick-actions">
            <button onClick={() => handleQuickAction('fees')}>
              <CreditCard size={14} /> Fees
            </button>
            <button onClick={() => handleQuickAction('attendance')}>
              <TrendingUp size={14} /> Attendance
            </button>
            <button onClick={() => handleQuickAction('schedule')}>
              <Calendar size={14} /> Schedule
            </button>
            <button onClick={() => handleQuickAction('assignments')}>
              <BookOpen size={14} /> Assignments
            </button>
          </div>

          {/* Suggestions */}
          {suggestions.length > 0 && (
            <div className="chat-suggestions">
              <p className="suggestions-label">Try asking:</p>
              <div className="suggestions-grid">
                {suggestions.map((suggestion, index) => (
                  <button
                    key={index}
                    className="suggestion-chip"
                    onClick={() => handleQuickAction(suggestion)}
                  >
                    {suggestion}
                    <ChevronRight size={12} />
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Chat Input */}
          <div className="chat-input-container">
            <input
              type="text"
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Ask about fees, grades, schedule, etc..."
              disabled={isAiTyping}
              className="chat-input"
            />
            <button 
              className="chat-send"
              onClick={() => handleSendMessage()}
              disabled={!userInput.trim() || isAiTyping}
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>

      {/* Dashboard Insights */}
      {insights.length > 0 && (
        <div className="insights-section">
          {insights.map((insight, index) => (
            <div 
              key={index} 
              className={`insight-card ${insight.type}`}
              onClick={insight.action}
            >
              <div className="insight-icon">{insight.icon}</div>
              <div className="insight-text">{insight.text}</div>
              <ChevronRight size={16} className="insight-arrow" />
            </div>
          ))}
        </div>
      )}

      {/* Main Dashboard Content */}
      <header className="top-header">
        <div className="student-left">
          <div className="avatar">
            {student.photoPath ? (
              <img src={`http://localhost:65000/${student.photoPath}`} alt="student" />
            ) : (
              <div className="initial">
                {student.name.fullName ? student.name.fullName.charAt(0).toUpperCase() : 'S'}
              </div>
            )}
          </div>
          <div>
            <h1>{student.name.fullName}</h1>
            <div className="sub">{student.studentId} • {student.departmentCode} {student.department}</div>
            <div className="sub small">{student.universityEmail} • {student.contactNumber}</div>
            <div className="badge">{student.degreeLevel} • {student.section}</div>
          </div>
        </div>

        <div className="right-stats">
          <div className="stat">
            <div className="label">Cumulative GPA</div>
            <div className="value">{academicProgress.cumulativeGPA?.toFixed(2) ?? '-'}</div>
          </div>
          <div className="stat">
            <div className="label">Total Credits</div>
            <div className="value">{academicProgress.totalCreditsEarned}/{academicProgress.totalCreditsRequired}</div>
          </div>
          <div className="stat">
            <div className="label">Progress</div>
            <div className="value">{academicProgress.completionPercentage ?? percentProgress}%</div>
          </div>
        </div>
      </header>

      <section className="summary-cards">
        <div className="card">
          <h3>Degree Progress</h3>
          <div className="progress-line">
            <div className="fill" style={{ width: `${percentProgress}%` }} />
          </div>
          <div className="muted">Completed {academicProgress.totalCreditsEarned} of {academicProgress.totalCreditsRequired} credits</div>
          <div className="muted">Scholarship: {student.scholarship.isApplicant ? `${student.scholarship.percentage}%` : 'N/A'}</div>
        </div>

        <div className="card">
          <h3>Current Semester (#{academicProgress.currentSemester})</h3>
          <div className="metric-row">
            <div>
              <div className="metric-label">Semester GPA</div>
              <div className="metric-value">{current.semesterGPA?.toFixed(2) ?? '-'}</div>
            </div>
            <div>
              <div className="metric-label">Credits Attempted</div>
              <div className="metric-value">{current.creditsAttempted ?? 0}</div>
            </div>
            <div>
              <div className="metric-label">Credits Earned</div>
              <div className="metric-value">{current.creditsEarned ?? 0}</div>
            </div>
            <div>
              <div className="metric-label">Quality Points</div>
              <div className="metric-value">{current.qualityPoints ?? 0}</div>
            </div>
          </div>
          <div className="muted">
            {current.startDate ? `Period: ${new Date(current.startDate).toLocaleDateString()} - ${new Date(current.endDate).toLocaleDateString()}` : ''}
          </div>
        </div>

        <div className="card">
          <h3>Quick Actions</h3>
          <div style={{display: 'flex', gap: 8, flexWrap: 'wrap'}}>
            <button onClick={() => handleQuickAction('fees')} className="btn action-btn">
              <CreditCard size={14} /> Check Fees
            </button>
            <button onClick={() => handleQuickAction('schedule')} className="btn action-btn">
              <Calendar size={14} /> Today's Schedule
            </button>
            <button onClick={() => setShowAllSemesters(s => !s)} className="btn alt">
              {showAllSemesters ? 'Hide' : 'Show'} Semesters
            </button>
            <button onClick={loadDashboard} className="btn ghost">
              Refresh
            </button>
          </div>
        </div>
      </section>

      <section className="courses-section">
        <h2>Enrolled Courses - Current Semester</h2>
        <div className="courses-grid">
          {(current.courses || []).length === 0 && <div className="muted">No courses found for current semester.</div>}

          {(current.courses || []).map((c, idx) => (
            <div key={idx} className="course-card">
              <div className="course-top">
                <div>
                  <div className="course-code">{c.courseCode || '—'}</div>
                  <div className="course-name">{c.courseName || 'Untitled Course'}</div>
                </div>
                <div className="course-meta">
                  <div className={`status ${c.status?.toLowerCase()}`}>{c.status ?? 'N/A'}</div>
                  <div className="grade">{c.grade ?? '-'}</div>
                </div>
              </div>

              <div className="course-body">
                <div>Credits: <strong>{c.creditsEarned ?? 0}</strong></div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {showAllSemesters && (
        <section className="semesters-section">
          <h2>All Semesters</h2>
          <div className="sem-table">
            <div className="row header">
              <div>Semester</div><div>Status</div><div>GPA</div><div>Credits</div><div>Period</div><div>Courses</div>
            </div>
            {(academicProgress.allSemesters || []).map((s, i) => (
              <div key={i} className="row">
                <div>{s.semesterNumber}</div>
                <div>{s.status}</div>
                <div>{s.semesterGPA?.toFixed(2) || '-'}</div>
                <div>{s.creditsEarned}/{s.creditsAttempted}</div>
                <div>{s.startDate ? `${new Date(s.startDate).toLocaleDateString()} - ${new Date(s.endDate).toLocaleDateString()}` : '-'}</div>
                <div>
                  {(s.courses || []).map((cc, idx) => (
                    <div key={idx} className="mini-course">
                      <strong>{cc.courseCode}</strong> • {cc.courseName} • {cc.grade ?? '-'}
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Comprehensive Styles */}
      <style>{`
        .dashboard-root { 
          padding: 28px; 
          font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue"; 
