        .chatbot-widget.open .chatbot-container {
          opacity: 1;
          transform: translateY(0);
          pointer-events: all;
        }
        
        .chat-header {
          padding: 16px;
          border-bottom: 1px solid #eef2ff;
          display: flex;
          justify-content: space-between;
          align-items: center;
