        }
        
        .chat-message.user {
          align-self: flex-end;
          flex-direction: row-reverse;
        }
        
        .chat-message.system {
          background: #f8fafc;
          border-radius: 12px;
          padding: 12px;
          max-width: 100%;
        }
        
        .chat-message.error {
          border-left: 3px solid #ef4444;
        }
        
        .message-avatar {
          width: 32px;
          height: 32px;
          border-radius: 50%;
          background: #eef2ff;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
          margin-top: 4px;
        }
        
        .message-avatar svg {
          color: #2563eb;
        }
        
        .chat-message.user .message-avatar {
          background: #2563eb;
        }
        
        .chat-message.user .message-avatar svg {
          color: white;
        }
        
        .message-content {
          flex: 1;
        }
        
        .message-text {
          background: #f8fafc;
          padding: 12px 16px;
          border-radius: 12px;
          font-size: 14px;
          line-height: 1.5;
          color: #0f172a;
        }
        
        .chat-message.user .message-text {
          background: #2563eb;
          color: white;
        }
        
        .chat-message.system .message-text {
          background: transparent;
          padding: 0;
        }
        
        .message-meta {
          display: flex;
          gap: 8px;
          align-items: center;
          margin-top: 4px;
          font-size: 11px;
          color: #64748b;
        }
        
        .chat-message.user .message-meta {
          justify-content: flex-end;
        }
        
        .message-duration {
          display: flex;
          align-items: center;
          gap: 4px;
        }
        
        .typing-indicator {
