        }
        
        .course-code { 
          font-weight: 700; 
          color: #0f172a; 
        }
        
        .course-name { 
          color: #475569; 
          margin-top: 6px; 
        }
        
        .course-meta { 
          text-align: right; 
        }
        
        .status { 
          padding: 6px 8px; 
          border-radius: 8px; 
          font-size: 12px; 
          font-weight: 700; 
          display: inline-block;
        }
        
        .status.completed { 
          background: #ecfeff; 
          color: #065f46; 
        }
        
        .status.enrolled { 
          background: #eef2ff; 
          color: #1e40af; 
        }
        
        .status.dropped { 
          background: #fff1f2; 
          color: #9f1239; 
        }
        
        .grade { 
          font-weight: 800; 
          margin-top: 8px; 
        }
        
        .sem-table { 
          background: #fff; 
          padding: 12px; 
          border-radius: 10px; 
          margin-top: 10px; 
        }
        
        .row { 
          display: grid; 
          grid-template-columns: 60px 90px 80px 120px 220px 1fr; 
          gap: 12px; 
          padding: 8px 10px; 
          align-items: center; 
          border-bottom: 1px solid #f1f5f9; 
        }
        
        .row.header { 
          font-weight: 700; 
          color: #0f172a; 
          background: #f8fafc; 
          border-bottom: 1px solid #e6eefc; 
        }
        
        .mini-course { 
          font-size: 13px; 
          color: #475569; 
          margin-bottom: 6px; 
        }
        
        .muted {
          color: #64748b;
          font-size: 14px;
          margin-top: 4px;
        }
        
        /* Responsive Design */
        @media (max-width: 1200px) {
          .summary-cards {
            grid-template-columns: 1fr 1fr;
          }
        }
        
        @media (max-width: 768px) {
          .dashboard-root {
            padding: 16px;
          }
          
          .summary-cards {
            grid-template-columns: 1fr;
          }
          
          .top-header {
            flex-direction: column;
            align-items: flex-start;
            gap: 16px;
          }
          
          .right-stats {
            width: 100%;
            justify-content: space-between;
          }
          
          .stat {
            min-width: 100px;
          }
          
          .chatbot-container {
            width: calc(100vw - 32px);
            right: -16px;
          }
          
          .row {
            grid-template-columns: 60px 90px 80px 120px 200px;
            overflow-x: auto;
          }
          
          .row > div:last-child {
            min-width: 200px;
          }
        }
      `}</style>
    </div>
  );
};

export default StudentDashboard;
